<?php require_once dirname(__DIR__).'/includes/auth.php'; require_login();
if($_SERVER['REQUEST_METHOD']==='POST' && ($_POST['_action']??'')==='delete'){ if(verify_csrf($_POST['csrf_token']??'')) db()->prepare('DELETE FROM contact_submissions WHERE id=?')->execute([(int)$_POST['id']]); redirect('contact_messages.php'); }
$pageTitle='Contact Messages'; $rows=db()->query('SELECT * FROM contact_submissions ORDER BY created_at DESC')->fetchAll(); include __DIR__.'/includes/header.php'; ?>
<div class="panel"><table class="data-table"><thead><tr><th>Name</th><th>Email</th><th>Subject</th><th>Message</th><th>Date</th><th></th></tr></thead><tbody><?php if(!$rows):?><tr><td colspan="6" class="empty">No messages yet.</td></tr><?php endif; foreach($rows as $r):?><tr><td><?= e($r['first_name'].' '.$r['last_name']) ?></td><td><?= e($r['email']) ?></td><td><?= e($r['subject']) ?></td><td><?= e(mb_strimwidth($r['message'],0,120,'...')) ?></td><td><?= e(date('d M Y',strtotime($r['created_at']))) ?></td><td><form method="post" class="confirm-delete"><?= csrf_field() ?><input type="hidden" name="_action" value="delete"><input type="hidden" name="id" value="<?= (int)$r['id'] ?>"><button class="link-danger">Delete</button></form></td></tr><?php endforeach;?></tbody></table></div>
